3		import type { RunDetail } from './+page'
4	
5		let { data }: { data: PageData } = $props()
6	
7		const run: RunDetail | null = data.run
8	
9		function runsListHref(): string {
10			return `/nodes/${data.nodeId}/projects/${data.projectId}/runs`
11		}
12	
13		function parentRunHref(parentId: string): string {
14			return `/nodes/${data.nodeId}/projects/${data.projectId}/runs/${parentId}`
15		}
16	
17		function childRunHref(childId: string): string {
18			return `/nodes/${data.nodeId}/projects/${data.projectId}/runs/${childId}`
19		}
20	
21		function beadHref(beadId: string): string {
22			return `/nodes/${data.nodeId}/projects/${data.projectId}/beads/${beadId}`
23		}
24	
25		function fmtDate(iso: string | null): string {
26			if (!iso) return '—'
27			return new Date(iso).toLocaleString()
28		}
29	
30		function fmtDuration(ms: number | null): string {
31			if (ms == null) return '—'
32			if (ms < 1000) return `${ms}ms`
33			if (ms < 60_000) return `${(ms / 1000).toFixed(1)}s`
34			const m = Math.floor(ms / 60_000)
35			const s = Math.floor((ms % 60_000) / 1000)
36			return `${m}m ${s}s`
37		}
38	
39		function layerBadgeClass(layer: string): string {
40			switch (layer) {
41				case 'work':
42					return 'bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-300'
43				case 'try':
44					return 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300'
45				case 'run':
46					return 'bg-teal-100 text-teal-800 dark:bg-teal-900/30 dark:text-teal-300'
47				default:
48					return 'bg-bg-surface text-fg-muted dark:bg-dark-bg-surface dark:text-dark-fg-muted'
49			}
50		}
51	
52		function statusBadgeClass(status: string): string {
53			switch (status) {
54				case 'success':
55					return 'badge-status-closed'
56				case 'failure':
57					return 'badge-status-failed'
58				case 'running':
59					return 'badge-status-running'
60				case 'preserved':
61					return 'badge-status-in-progress'
62				default:
63					return 'badge-status-open'
64			}
65		}
